2649: 	struct azx *chip = card->private_data;
2650: 	bool disabled;
2651: 
2652: 	if (chip->init_failed)
2653: 		return;
2654: 
2655: 	disabled = (state == VGA_SWITCHEROO_OFF);
2656: 	if (chip->disabled == disabled)
2657: 		return;
