2665: 			if (azx_first_init(chip) < 0 ||
2666: 			    azx_probe_continue(chip) < 0) {
2667: 				snd_printk(KERN_ERR SFX
2668: 					   "%s: initialization error\n",
2669: 					   pci_name(chip->pci));
2670: 				chip->init_failed = true;
2671: 			}
2672: 		}
2673: 	} else {
2674: 		snd_printk(KERN_INFO SFX
2675: 			   "%s %s via VGA-switcheroo\n",
2676: 			   disabled ? "Disabling" : "Enabling",
2677: 			   pci_name(chip->pci));
2678: 		if (disabled) {
2679: 			azx_suspend(&pci->dev);
2680: 			chip->disabled = true;
2681: 			if (snd_hda_lock_devices(chip->bus))
2682: 				snd_printk(KERN_WARNING SFX
2683: 					   "Cannot lock devices!\n");
2684: 		} else {
2685: 			snd_hda_unlock_devices(chip->bus);
2686: 			chip->disabled = false;
2687: 			azx_resume(&pci->dev);
2688: 		}
2689: 	}
2690: }
